{
  "title": "DBMS 2 Classroom Quiz - May 11, 2026",
  "difficulty": "medium",
  "questions": [
    {
      "id": "q1",
      "question": "In the Three-Schema Architecture, which level of abstraction describes what data is stored in the database and what relationships exist among that data?",
      "options": {
        "A": "Physical level",
        "B": "Logical level",
        "C": "View level",
        "D": "Internal level"
      },
      "answer": "B",
      "explanation": "The logical level describes what data is stored and their relationships, while the physical level describes how it is stored."
    },
    {
      "id": "q2",
      "question": "Which of the following statements best describes the relationship between data and information?",
      "options": {
        "A": "Data depends on information to exist.",
        "B": "Information is raw and unorganized facts.",
        "C": "Information depends on data, but data does not depend on information.",
        "D": "Data is presented through thoughts and ideas, while information is numerical."
      },
      "answer": "C",
      "explanation": "Information is extracted from data by processing and analyzing it; data does not require information to exist."
    },
    {
      "id": "q3",
      "question": "In a 3-Tier (T3) Architecture, where is the business logic typically located?",
      "options": {
        "A": "Client machine",
        "B": "Database system",
        "C": "Application server",
        "D": "API standard"
      },
      "answer": "C",
      "explanation": "In T3 architecture, the client is just a frontend and the business logic resides in the application server."
    },
    {
      "id": "q4",
      "question": "Which type of attribute is represented by a person's name being divided into first-name, middle-name, and last-name?",
      "options": {
        "A": "Simple attribute",
        "B": "Multi-valued attribute",
        "C": "Derived attribute",
        "D": "Composite attribute"
      },
      "answer": "D",
      "explanation": "Composite attributes can be divided into subparts such as a name split into first, middle, and last components."
    },
    {
      "id": "q5",
      "question": "According to the class notes, how is a 'Database Schema' best defined in programming terms?",
      "options": {
        "A": "It corresponds to the values stored in variables.",
        "B": "It corresponds to the variable declarations and their types.",
        "C": "It is the set of programs used to access data.",
        "D": "It is the actual data stored at a particular moment."
      },
      "answer": "B",
      "explanation": "The schema is the overall structural design, similar to how variable declarations define a program's structure."
    },
    {
      "id": "q6",
      "question": "Which constraint is specifically defined as the number of entities to which another entity can be associated via a relationship?",
      "options": {
        "A": "Participation Constraint",
        "B": "Mapping Cardinality",
        "C": "Degree of Relationship",
        "D": "Specialization"
      },
      "answer": "B",
      "explanation": "Mapping cardinality or cardinality ratio expresses the number of entities associated with another entity via a relationship."
    },
    {
      "id": "q7",
      "question": "What is the primary characteristic of a 'Weak Entity' in the ER Model?",
      "options": {
        "A": "It can be uniquely identified by its own attributes.",
        "B": "It does not depend on any other entity for existence.",
        "C": "It cannot be uniquely identified and depends on a strong entity.",
        "D": "It always has partial participation in a relationship."
      },
      "answer": "C",
      "explanation": "Weak entities lack sufficient attributes to be uniquely identified and depend on a strong entity to exist."
    },
    {
      "id": "q8",
      "question": "Which approach does 'Specialization' follow when subgrouping an entity set into distinct sub-entity sets?",
      "options": {
        "A": "Bottom-Up approach",
        "B": "Middle-Out approach",
        "C": "Top-Down approach",
        "D": "Circular approach"
      },
      "answer": "C",
      "explanation": "Specialization is a top-down approach that splits an entity set based on specific functionalities or features."
    }
  ]
}
